// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

interface ISGLBurnable is IERC20 {
    function burn(uint256 amount) external;
}

/// @title FeeManager
/// @notice Stub de taxas para capsulas, oraculos e fluxos de entrega em SGL.
/// @dev Proximo passo: integrar fee routing por modulo, multisig e politicas de AML/KYC.
contract FeeManager is AccessControl, Pausable {
    using SafeERC20 for IERC20;

    bytes32 public constant TREASURER_ROLE = keccak256("TREASURER_ROLE");

    uint16 public constant MAX_BPS = 10_000;

    ISGLBurnable public immutable sglToken;
    address public treasury;
    uint16 public platformFeeBps;
    uint16 public burnFeeBps;

    event FeeCollected(address indexed payer, uint256 indexed baseAmount, uint256 treasuryAmount, uint256 burnedAmount);
    event FeeConfigUpdated(uint16 platformFeeBps, uint16 burnFeeBps, address treasury);

    constructor(address tokenAddress, address treasuryAddress, uint16 platformBps, uint16 burnBps) {
        require(tokenAddress != address(0), "FEE: invalid token");
        require(treasuryAddress != address(0), "FEE: invalid treasury");
        require(platformBps + burnBps <= MAX_BPS, "FEE: invalid bps");

        sglToken = ISGLBurnable(tokenAddress);
        treasury = treasuryAddress;
        platformFeeBps = platformBps;
        burnFeeBps = burnBps;

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(TREASURER_ROLE, msg.sender);
    }

    function quoteFee(uint256 baseAmount) public view returns (uint256 treasuryAmount, uint256 burnedAmount, uint256 totalFee) {
        treasuryAmount = (baseAmount * platformFeeBps) / MAX_BPS;
        burnedAmount = (baseAmount * burnFeeBps) / MAX_BPS;
        totalFee = treasuryAmount + burnedAmount;
    }

    function collectFee(address payer, uint256 baseAmount) external whenNotPaused onlyRole(TREASURER_ROLE) returns (uint256 totalFee) {
        require(payer != address(0), "FEE: invalid payer");

        (uint256 treasuryAmount, uint256 burnedAmount, uint256 total) = quoteFee(baseAmount);
        totalFee = total;

        if (totalFee == 0) {
            return 0;
        }

        IERC20(address(sglToken)).safeTransferFrom(payer, address(this), totalFee);

        if (treasuryAmount > 0) {
            IERC20(address(sglToken)).safeTransfer(treasury, treasuryAmount);
        }

        if (burnedAmount > 0) {
            sglToken.burn(burnedAmount);
        }

        emit FeeCollected(payer, baseAmount, treasuryAmount, burnedAmount);
    }

    function setFeeConfig(address newTreasury, uint16 newPlatformFeeBps, uint16 newBurnFeeBps)
        external
        onlyRole(DEFAULT_ADMIN_ROLE)
    {
        require(newTreasury != address(0), "FEE: invalid treasury");
        require(newPlatformFeeBps + newBurnFeeBps <= MAX_BPS, "FEE: invalid bps");

        treasury = newTreasury;
        platformFeeBps = newPlatformFeeBps;
        burnFeeBps = newBurnFeeBps;

        emit FeeConfigUpdated(newPlatformFeeBps, newBurnFeeBps, newTreasury);
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

contracts/SGLToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/// @title SGLToken
/// @notice Stub seguro do token SGL para evolucao no Hardhat.
/// @dev Proximo passo: integrar multisig treasury, AvatarPro e politicas de emissao governadas.
contract SGLToken is ERC20Burnable, AccessControl, Pausable {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");

    address public treasury;

    event TreasuryUpdated(address indexed previousTreasury, address indexed newTreasury);
    event Minted(address indexed to, uint256 amount, address indexed operator);

    constructor(address initialTreasury, uint256 initialSupply) ERC20("SingulAI Token", "SGL") {
        require(initialTreasury != address(0), "SGL: invalid treasury");

        treasury = initialTreasury;

        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(PAUSER_ROLE, msg.sender);

        _mint(initialTreasury, initialSupply);
        emit Minted(initialTreasury, initialSupply, msg.sender);
    }

    function setTreasury(address newTreasury) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newTreasury != address(0), "SGL: invalid treasury");

        address previousTreasury = treasury;
        treasury = newTreasury;

        emit TreasuryUpdated(previousTreasury, newTreasury);
    }

    function mint(address to, uint256 amount) external onlyRole(MINTER_ROLE) {
        require(to != address(0), "SGL: invalid recipient");

        _mint(to, amount);
        emit Minted(to, amount, msg.sender);
    }

    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }

    function _update(address from, address to, uint256 value) internal override whenNotPaused {
        super._update(from, to, value);
    }
}

contracts/StakingPool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/// @title StakingPool
/// @notice Stub seguro de staking para SGL com distribuicao simples de recompensas.
/// @dev Proximo passo: incorporar slashing, reward epochs e governance hooks.
contract StakingPool is AccessControl, ReentrancyGuard, Pausable {
    using SafeERC20 for IERC20;

    bytes32 public constant REWARD_DISTRIBUTOR_ROLE = keccak256("REWARD_DISTRIBUTOR_ROLE");

    IERC20 public immutable stakingToken;
    IERC20 public immutable rewardToken;

    uint256 public rewardRate;
    uint256 public lastUpdateTime;
    uint256 public rewardPerTokenStored;
    uint256 public periodFinish;
    uint256 public totalStaked;

    mapping(address => uint256) public balances;
    mapping(address => uint256) public userRewardPerTokenPaid;
    mapping(address => uint256) public rewards;

    event Staked(address indexed user, uint256 amount);
    event Withdrawn(address indexed user, uint256 amount);
    event RewardPaid(address indexed user, uint256 reward);
    event RewardAdded(uint256 reward, uint256 duration);

    constructor(address stakingTokenAddress, address rewardTokenAddress, address admin, address rewardDistributor) {
        require(stakingTokenAddress != address(0), "STAKING: invalid staking token");
        require(rewardTokenAddress != address(0), "STAKING: invalid reward token");
        require(admin != address(0), "STAKING: invalid admin");
        require(rewardDistributor != address(0), "STAKING: invalid distributor");

        stakingToken = IERC20(stakingTokenAddress);
        rewardToken = IERC20(rewardTokenAddress);

        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(REWARD_DISTRIBUTOR_ROLE, rewardDistributor);
    }

    modifier updateReward(address account) {
        rewardPerTokenStored = rewardPerToken();
        lastUpdateTime = lastTimeRewardApplicable();

        if (account != address(0)) {
            rewards[account] = earned(account);
            userRewardPerTokenPaid[account] = rewardPerTokenStored;
        }

        _;
    }

    function lastTimeRewardApplicable() public view returns (uint256) {
        return block.timestamp < periodFinish ? block.timestamp : periodFinish;
    }

    function rewardPerToken() public view returns (uint256) {
        if (totalStaked == 0) {
            return rewardPerTokenStored;
        }

        return rewardPerTokenStored + (((lastTimeRewardApplicable() - lastUpdateTime) * rewardRate * 1e18) / totalStaked);
    }

    function earned(address account) public view returns (uint256) {
        return ((balances[account] * (rewardPerToken() - userRewardPerTokenPaid[account])) / 1e18) + rewards[account];
    }

    function stake(uint256 amount) external nonReentrant whenNotPaused updateReward(msg.sender) {
        require(amount > 0, "STAKING: zero amount");

        totalStaked += amount;
        balances[msg.sender] += amount;
        stakingToken.safeTransferFrom(msg.sender, address(this), amount);

        emit Staked(msg.sender, amount);
    }

    function withdraw(uint256 amount) public nonReentrant whenNotPaused updateReward(msg.sender) {
        require(amount > 0, "STAKING: zero amount");
        require(balances[msg.sender] >= amount, "STAKING: insufficient balance");

        totalStaked -= amount;
        balances[msg.sender] -= amount;
        stakingToken.safeTransfer(msg.sender, amount);

        emit Withdrawn(msg.sender, amount);
    }

    function claimReward() public nonReentrant whenNotPaused updateReward(msg.sender) {
        uint256 reward = rewards[msg.sender];
        require(reward > 0, "STAKING: no reward");

        rewards[msg.sender] = 0;
        rewardToken.safeTransfer(msg.sender, reward);

        emit RewardPaid(msg.sender, reward);
    }

    function exit() external {
        withdraw(balances[msg.sender]);
        claimReward();
    }

    function notifyRewardAmount(uint256 reward, uint256 duration)
        external
        onlyRole(REWARD_DISTRIBUTOR_ROLE)
        updateReward(address(0))
    {
        require(duration > 0, "STAKING: invalid duration");

        rewardToken.safeTransferFrom(msg.sender, address(this), reward);

        if (block.timestamp >= periodFinish) {
            rewardRate = reward / duration;
        } else {
            uint256 remaining = periodFinish - block.timestamp;
            uint256 leftover = remaining * rewardRate;
            rewardRate = (reward + leftover) / duration;
        }

        lastUpdateTime = block.timestamp;
        periodFinish = block.timestamp + duration;

        emit RewardAdded(reward, duration);
    }

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }
}

